class Employe { public virtual void Travailler() { Console.WriteLine("L'employé travaille"); } }
class Developpeur : Employe { public override void Travailler() { Console.WriteLine("Le développeur écrit du code"); } }
class Manager : Employe { public override void Travailler() { Console.WriteLine("Le manager supervise l'équipe"); } }

static void AfficherTravail(Employe e) { e.Travailler(); }

Developpeur d = new Developpeur();
Manager m = new Manager();
AfficherTravail(d); // Le développeur écrit du code
AfficherTravail(m); // Le manager supervise l'équipe

class CompteBancaire { public virtual double CalculerInterets(double solde) { return solde * 0.05; } }
class CompteEpargne : CompteBancaire { public override double CalculerInterets(double solde) { return solde * 0.08; } }
class CompteCourant : CompteBancaire { public new double CalculerInterets(double solde) { return solde * 0.02; } }

CompteBancaire[] comptes = { new CompteEpargne(), new CompteCourant() };
foreach(var c in comptes) Console.WriteLine(c.CalculerInterets(1000)); // Affiche 80 puis 50 (car new ne respecte pas le polymorphisme)
// Le CompteCourant est traité comme un CompteBancaire, donc c'est la méthode de la classe de base qui est appelée.
